import{_ as a,o as t,c as n,a3 as i}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"35. Advertising And Filling Vacancies","description":"","frontmatter":{"title":"35. Advertising And Filling Vacancies","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["staffing"]},"headers":[],"relativePath":"ebas/mspp/workforce-management/35-advertising-and-filling-vacancies.md","filePath":"ebas/mspp/workforce-management/35-advertising-and-filling-vacancies.md"}'),o={name:"ebas/mspp/workforce-management/35-advertising-and-filling-vacancies.md"};function s(r,e,c,l,p,d){return t(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="_35-advertising-and-filling-vacancies" tabindex="-1">35. Advertising And Filling Vacancies <a class="header-anchor" href="#_35-advertising-and-filling-vacancies" aria-label="Permalink to &quot;35. Advertising And Filling Vacancies&quot;">​</a></h1><p><strong>35.1</strong> Subject clause 35.3, each vacancy that arises will be filled by the Employer.</p><p><strong>35.2</strong> The process for advertising a vacant position will be as follows:</p><p><strong>a.</strong> Immediately once it is known that a position will become vacant, the responsible manager/supervisor will commence the appropriate action to advertise the vacant position.</p><p><strong>b.</strong> In relation to a above, the vacant position will be advertised as quickly as possible after the Employer becomes aware the position will or has become vacant.</p><p><strong>c.</strong> The vacant position will be advertised and offered at the employment status, classification grade level and time fraction (as a minimum) of the Employee who vacated the position.</p><p><strong>d.</strong> During any period between a position becoming vacant and the position being filled, the Employer will be either:</p><p><strong>(i)</strong> Backfill the vacant position in accordance with <a href="/eba/ebas/mspp/workforce-management/34-planned-and-unplanned-absences.html">clause 34</a>; or</p><p><strong>(ii)</strong> Prioritise work in the area the vacancy has occurred to ensure the work that was done by the Employee who has left is not required to be undertaken by any other staff member/s; or</p><p><strong>(iii)</strong> Prioritise work in the area the vacancy has arisen to ensure workloads of staff members/s who may be asked to perform the priority duties of the vacant position are adjusted by reducing their normal duties.</p><p><strong>35.3</strong> Where an Employer elects to make changes to the vacant position, the Employer shall enter into immediate consultation in accordance with <a href="/eba/ebas/mspp/employment/30-consultation.html">clause 30</a>.</p><p>Plain language terms: recruitment, vacancy filling.</p>',12)])])}const h=a(o,[["render",s]]);export{g as __pageData,h as default};
